        },
        "endpoint_family": {
          "type": "string"
        },
        "time_horizon": {
          "type": "string"
        },
        "effect_metric": {
          "type": "string"
        },
        "variance_model": {
          "type": "string"
        }
      }
    },
    "outcome_ids": {
      "type": "array",
      "minItems": 1,
      "items": {
        "$ref": "./common.schema.json#/$defs/outcomeRef"
      },
      "uniqueItems": true
    },
    "result_ids": {
      "type": "array",
      "minItems": 1,
      "items": {
        "$ref": "./common.schema.json#/$defs/resultRef"
      },
      "uniqueItems": true
    },
    "compatibility_status": {
      "enum": [
        "poolable",
        "not_poolable",
        "needs_extraction",
        "mixed"
      ]
    },
    "pooling_decision": {
      "enum": [
        "pooling_allowed",
        "pooling_blocked",
        "pooling_pending"
      ]
    },
    "pooling_rationale": {
      "type": "string"
    },
    "non_pooling_reason": {
      "type": "string"
    },
    "pooling_requirements": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "minimum_result_count",
        "required_result_maturity_statuses",
        "required_effect_fields",
        "missing_effect_fields_by_result"
      ],
      "properties": {
        "minimum_result_count": {
          "type": "integer",
          "minimum": 2
        },
        "required_result_maturity_statuses": {
          "type": "array",
          "items": {
            "$ref": "./common.schema.json#/$defs/maturityStatus"
          },
          "uniqueItems": true
        },
        "required_effect_fields": {
          "type": "array",
          "minItems": 1,
          "items": {
            "$ref": "#/$defs/poolingRequirementField"
          },
          "uniqueItems": true
        },
        "missing_effect_fields_by_result": {
